import requests

BASE_URL = "http://localhost:3000"
TIMEOUT = 30

# Replace with a valid Bearer token for authorization testing
VALID_BEARER_TOKEN = "your_valid_bearer_token_here"

def test_post_api_chat_streams_responses_and_persists_messages():
    url = f"{BASE_URL}/api/chat"
    headers = {
        "Authorization": f"Bearer {VALID_BEARER_TOKEN}",
        "Content-Type": "application/json"
    }
    valid_payload = {
        "messages": [
            {"role": "user", "content": "Hello AI agent, please assist me."}
        ]
    }
    invalid_payload = {
        "messages": []
    }

    # Test 1: POST /api/chat with valid authorization and valid payload
    response = requests.post(url, json=valid_payload, headers=headers, timeout=TIMEOUT)
    try:
        assert response.status_code != 401, f"Unauthorized: Bearer token invalid or missing. Got status {response.status_code}"
        assert response.status_code == 200, f"Expected 200 OK, got {response.status_code}"
        text = response.text
        assert isinstance(text, str) and len(text) > 0, "Response text should not be empty"
        assert "user" in text or "assistant" in text or "AI" in text or "message" in text.lower(), "Response should include AI chat content"
    except AssertionError:
        raise
    except Exception as e:
        raise AssertionError(f"Unexpected error while validating valid authorized chat response: {e}")

    # Test 2: POST /api/chat without Authorization header -> Expect 401 Unauthorized
    response_unauth = requests.post(url, json=valid_payload, timeout=TIMEOUT)
    try:
        assert response_unauth.status_code == 401, f"Expected 401 Unauthorized, got {response_unauth.status_code}"
    except AssertionError:
        raise
    except Exception as e:
        raise AssertionError(f"Unexpected error while validating unauthorized chat request: {e}")

    # Test 3: POST /api/chat with valid authorization but invalid payload -> Expect 400 Bad Request
    response_bad_request = requests.post(url, json=invalid_payload, headers=headers, timeout=TIMEOUT)
    try:
        assert response_bad_request.status_code == 400, f"Expected 400 Bad Request, got {response_bad_request.status_code}"
    except AssertionError:
        raise
    except Exception as e:
        raise AssertionError(f"Unexpected error while validating bad request on invalid payload: {e}")

test_post_api_chat_streams_responses_and_persists_messages()

import requests

BASE_URL = "http://localhost:3000"
TIMEOUT = 30

# You must set this token value for authorization prior to running the test
AUTH_TOKEN = "your_valid_bearer_token_here"


def test_post_api_artifacts_generate_creates_artifact():
    url = f"{BASE_URL}/api/artifacts/generate"
    headers = {
        "Authorization": f"Bearer {AUTH_TOKEN}",
        "Content-Type": "application/json",
    }
    # Minimal valid payload for artifact generation - "prompt" is required
    payload = {
        "prompt": "Generate a test artifact for dental analysis"
    }

    try:
        response = requests.post(url, headers=headers, json=payload, timeout=TIMEOUT)
    except requests.RequestException as e:
        raise AssertionError(f"Request to {url} failed: {e}")

    if response.status_code == 200:
        try:
            artifact = response.json()
        except ValueError:
            raise AssertionError("Response body is not valid JSON")

        # Validate minimal expected keys in artifact response
        assert isinstance(artifact, dict), "Artifact response is not a JSON object"
        assert "id" in artifact or "_id" in artifact, "Artifact does not have an 'id' field"
        assert "prompt" in artifact, "Artifact response missing 'prompt' field"
        assert artifact["prompt"] == payload["prompt"], "Artifact prompt does not match request"
    elif response.status_code == 500:
        # Check error response for external model failure
        try:
            error_resp = response.json()
        except ValueError:
            raise AssertionError("500 response body is not valid JSON")

        assert "status" in error_resp, "Error response missing 'status' field"
        assert error_resp["status"].lower() in ("error", "internal server error", "fail", "failed", "500"), \
            "Error status not indicating server error"
    else:
        raise AssertionError(f"Unexpected status code: {response.status_code} - {response.text}")


test_post_api_artifacts_generate_creates_artifact()

import requests

BASE_URL = "http://localhost:3000"
TIMEOUT = 30

# These tokens should be replaced with valid tokens for the test environment
ADMIN_TOKEN = "your_admin_authorized_token_here"
NON_ADMIN_TOKEN = "your_non_admin_token_here"

def test_get_api_admin_users_lists_users_for_admin_only():
    headers_admin = {
        "Authorization": f"Bearer {ADMIN_TOKEN}"
    }
    headers_non_admin = {
        "Authorization": f"Bearer {NON_ADMIN_TOKEN}"
    }
    url = f"{BASE_URL}/api/admin/users"

    # Test with admin authorized token
    try:
        response_admin = requests.get(url, headers=headers_admin, timeout=TIMEOUT)
        assert response_admin.status_code == 200, f"Expected 200, got {response_admin.status_code}"
        data = response_admin.json()
        assert isinstance(data, list), "Expected response to be a list of users"
    except requests.RequestException as e:
        assert False, f"Request with admin token failed: {str(e)}"
    except ValueError:
        assert False, "Response with admin token is not a valid JSON"

    # Test with non-admin token
    try:
        response_non_admin = requests.get(url, headers=headers_non_admin, timeout=TIMEOUT)
        assert response_non_admin.status_code == 403, f"Expected 403, got {response_non_admin.status_code}"
    except requests.RequestException as e:
        assert False, f"Request with non-admin token failed: {str(e)}"

test_get_api_admin_users_lists_users_for_admin_only()
